function openVideoModal(id) {
  const drill = allDrills.find(d => d.id === id);
  if (!drill) return;
  const fileId = getDriveFileId(drill.gdrive_url);
  if (!fileId) return;
  const embedUrl = `https://drive.google.com/file/d/${fileId}/preview`;
  const title = escHtml(drill.sub_skill || drill.canonical_term || drill.id);
  const cue   = escHtml(drill.coaching_cue || '');
