  backdrop.className = 'video-modal-backdrop';
  backdrop.id = 'videoModal';
  backdrop.innerHTML =
    `<div class="video-modal-inner">` +
    `<iframe class="video-modal-iframe" src="${embedUrl}" allow="autoplay; encrypted-media" allowfullscreen></iframe>` +
    `<div class="video-modal-info"><h2>${title}</h2><p>${cue}</p></div>` +
    `</div>` +
    `<button class="video-modal-close" onclick="closeVideoModal()" title="Close">&times;</button>`;
