  if (drill) drill.skill_category = fromCat;
  renderVideos();
});
```

**CSS additions:**
```css
.video-strip.drop-target { outline: 2px dashed #e8b100; background: rgba(232,177,0,0.08); border-radius: 6px; }
.video-card[draggable="true"] { cursor: grab; }
.video-card[draggable="true"]:active { cursor: grabbing; }
```

---

### Phase 5 — Client: Hover overlay with Edit / Delete buttons

**On each `.video-card`, add an overlay div:**
```html
<div class="video-card-overlay">
  <button class="vco-btn" onclick="event.stopPropagation(); editDrill('${d.id}')">&#9998;</button>
  <button class="vco-btn vco-delete" onclick="event.stopPropagation(); deleteDrill('${d.id}')">&#10005;</button>
</div>
```

**CSS:**
```css
.video-card-overlay {
  position: absolute; top: 0; left: 0; right: 0;
  display: flex; justify-content: flex-end; gap: 6px; padding: 6px;
  opacity: 0; transition: opacity 0.15s; background: linear-gradient(180deg, rgba(0,0,0,0.6) 0%, transparent 100%);
}
