function videoDragStart(event, id, fromCat) {
  event.dataTransfer.effectAllowed = 'move';
  event.dataTransfer.setData('text/plain', JSON.stringify({ id: id, fromCat: fromCat }));
}

function videoDrop(event, toCat) {
  event.preventDefault();
  event.currentTarget.classList.remove('drop-target');
  var data;
  try { data = JSON.parse(event.dataTransfer.getData('text/plain')); } catch { return; }
  var id = data.id;
  var fromCat = data.fromCat;
  if (fromCat === toCat) return;
  var drill = allDrills.find(function(d) { return d.id === id; });
  if (!drill) return;
  // Optimistic update
  drill.skill_category = toCat;
  renderVideos();
  // Persist
  fetch('/api/drills/' + id, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ skill_category: toCat }),
  }).catch(function() {
    // Rollback on failure
    drill.skill_category = fromCat;
    renderVideos();
  });
}

